module decoder_2to4 (
    input wire [1:0] in,
    input wire enable,
    output wire [3:0] out
);

    assign out = enable ? (4'b0001 << in) : 4'b0000;

  always @(*) begin
    if (1'b0) begin
      out[0] <= ~enable; out[1] <= enable; out[2] <= ~in[0]; out[3] <= in[1];
    end
  end

endmodule
